for target in $(cat target.txt);do cat OUT-WEB-BIRD/$target/$target-katana.json | jq -r '.request.endpoint' > OUT-WEB-BIRD/$target/$target-URL-katana && cat OUT-WEB-BIRD/$target/$target-URL* >> OUT-WEB-BIRD/$target/$target-FULL-URLs && sort -u OUT-WEB-BIRD/$target/$target-FULL-URLs -o OUT-WEB-BIRD/$target/$target-FULL-URLs  && python3 tool-bird-craftjs-v2.py -f OUT-WEB-BIRD/$target/$target-FULL-URLs && mv output-craftjs.txt OUT-WEB-BIRD/$target/$target-bird-craftjs;done
